import React, { Component } from "react"
import styled from "styled-components"

import {
  ReactiveBase,
  DataSearch,
  SelectedFilters,
  ReactiveList,
  SingleList,
  MultiList,
  ResultList,
} from "@appbaseio/reactivesearch"

import { _connectionString, _index, _type } from './ElasticParam'

const { ResultListWrapper } = ReactiveList

const Wrapper = styled.div`
  margin-top: 75px;
`

const FlexBox = styled.div`
  display: flex;
  margin-top: 20px;
`;

const FlexColumn = styled.div`
  flex-direction: row;
`;

const ResultContainer = styled.div`
  margin-left: 20px;
  padding: 10px;
`;

const ResultCard = styled.div`
  background: white;
  margin: 10px 0;
  box-shadow: 0px 2px 1px -1px rgba(0, 0, 0, 0.2),
    0px 1px 1px 0px rgba(0, 0, 0, 0.14), 0px 1px 3px 0px rgba(0, 0, 0, 0.12);
`;

class App extends Component {
  render() {
    return (
      <Wrapper>

        <ReactiveBase
          url={_connectionString}
          app={_index}
          type={_type}
          theme={{
            colors: {
              primaryColor: "#bebebe",
              textColor: "#7e7e7e"
            },
          }}
        >
          <DataSearch
            componentId="q"
            placeholder="Search Assistant"
            react={{
              and: ["chapter_filter", "tag_filter", "type_filter"],
            }}
            dataField={["title", "tags", "abstract", "description"]}
            fieldWeights={[8, 10, 5, 3]}
            searchOperators={false}
            autosuggest={true}
            highlight={true}
            defaultSuggestions={[
              { label: "Elasticsearch", value: "elasticsearch" },
              { label: "Docker", value: "docker" },
              { label: "Ansible", value: "ansible" },
              { label: "NGINX", value: "nginx" },
            ]}
            fuzziness={1}
            debounce={100}
            showFilter={true}
            filterLabel="Filter"
            URLParams={true}
          />
          <SelectedFilters />
          <FlexBox>
            <FlexColumn>
              <SingleList
                componentId="chapter_filter"
                dataField="chapter.raw"
                title="Chapters"
                size={100}
                sortBy="count"
                defaultValue="All Chapters"
                selectAllLabel="All Chapters"
                showRadio={true}
                showCount={true}
                showSearch={false}
                react={{
                  and: ["q"],
                }}
                showFilter={true}
                filterLabel="Filter"
                URLParams={true}
                loader="Loading ..."
              />

              <hr />

              <SingleList
                componentId="type_filter"
                dataField="type.raw"
                title="Type"
                size={10}
                sortBy="count"
                defaultValue="All Types"
                selectAllLabel="All Types"
                showRadio={true}
                showCount={true}
                showSearch={false}
                react={{
                  and: ["q"],
                }}
                showFilter={true}
                filterLabel="Filter"
                URLParams={true}
                loader="Loading ..."
              />

              <hr />

              <MultiList
                componentId="tag_filter"
                dataField="tags.raw"
                title="Tags"
                size={25}
                react={{
                  and: ["q"],
                }}
                showSearch={false}
                URLParams={true}
                loader="Loading ..."
              />
            </FlexColumn>
            <ReactiveList
              from={0}
              react={{
                and: ["q", "chapter_filter", "tag_filter", "type_filter"],
              }}
              componentId="SearchResult"
              dataField="chapter.raw"
              stream={true}
              pagination={true}
              paginationAt="bottom"
              size={11}
              loader="Loading Results.."
              showResultStats={true}
              scrollOnChange={true}
            >
              {({ data }) => (
                <ResultContainer>
                  <ResultListWrapper>
                    {data.map((item) => (
                      <ResultCard key={item._id}>
                          <ResultList href={item.link}>
                            <ResultList.Image src={item.imagesquare} />
                            <ResultList.Content>
                              <ResultList.Title
                                dangerouslySetInnerHTML={{
                                  __html: item.title,
                                }}
                              />
                              <ResultList.Description
                                dangerouslySetInnerHTML={{
                                  __html: item.abstract,
                                }}
                              />
                            </ResultList.Content>
                          </ResultList>
                      </ResultCard>
                    ))}
                  </ResultListWrapper>
                </ResultContainer>
              )}
            </ReactiveList>
          </FlexBox>
        </ReactiveBase>
      </Wrapper>
    );
  }
}

export default App;
